#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding patient-intake (17 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_personal_information \
    assessment:references \
    first_name:string! \
    middle_name:string! \
    last_name:string! \
    preferred_name:string! \
    date_of_birth:date \
    sex:string! \
    gender_identity:string! \
    pronouns:string! \
    marital_status:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_needed:string! \
    phone_home:string! \
    phone_mobile:string! \
    phone_work:string! \
    email:string! \
    address_line_1:string! \
    address_line_2:string! \
    city:string! \
    county:string! \
    postcode:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    emergency_contact_relationship:string! \
    --htmx

cargo loco generate scaffold assessment_insurance_and_id \
    assessment:references \
    nhs_number:string! \
    hospital_number:string! \
    gp_name:string! \
    gp_practice:string! \
    gp_address:text! \
    gp_phone:string! \
    has_private_insurance:string! \
    insurance_provider:string! \
    insurance_policy_number:string! \
    insurance_group_number:string! \
    insurance_phone:string! \
    photo_id_verified:string! \
    photo_id_type:string! \
    insurance_notes:text! \
    --htmx

cargo loco generate scaffold assessment_reason_for_visit \
    assessment:references \
    visit_type:string! \
    primary_reason:text! \
    symptom_onset:text! \
    symptom_duration:text! \
    symptom_severity:int \
    symptoms_worsening:string! \
    previous_treatment_for_this:text! \
    referring_provider:string! \
    referral_reason:text! \
    patient_goals:text! \
    reason_for_visit_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    has_chronic_conditions:string! \
    has_diabetes:string! \
    diabetes_type:string! \
    has_hypertension:string! \
    has_heart_disease:string! \
    heart_disease_details:text! \
    has_lung_disease:string! \
    lung_disease_details:text! \
    has_kidney_disease:string! \
    has_liver_disease:string! \
    has_cancer:string! \
    cancer_details:text! \
    has_stroke:string! \
    has_epilepsy:string! \
    has_mental_health_condition:string! \
    mental_health_details:text! \
    has_autoimmune_disease:string! \
    autoimmune_disease_details:text! \
    has_previous_surgeries:string! \
    surgery_details:text! \
    has_hospitalisations:string! \
    hospitalisation_details:text! \
    other_conditions:text! \
    medical_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medications \
    assessment:references \
    takes_medications:string! \
    takes_over_the_counter:string! \
    takes_supplements:string! \
    supplement_details:text! \
    medication_adherence:string! \
    pharmacy_name:string! \
    pharmacy_phone:string! \
    medications_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medication_item \
    medications:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    route:string! \
    prescriber:string! \
    reason:string! \
    start_date:date \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_allergies \
    assessment:references \
    has_drug_allergies:string! \
    has_food_allergies:string! \
    has_environmental_allergies:string! \
    has_latex_allergy:string! \
    has_contrast_allergy:string! \
    has_anaesthetic_allergy:string! \
    history_of_anaphylaxis:string! \
    carries_epipen:string! \
    allergies_notes:text! \
    --htmx

cargo loco generate scaffold assessment_allergy_item \
    allergies:references \
    allergen:string! \
    allergy_type:string! \
    reaction:text! \
    severity:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_family_history \
    assessment:references \
    family_history_heart_disease:string! \
    family_history_stroke:string! \
    family_history_diabetes:string! \
    family_history_cancer:string! \
    family_cancer_details:text! \
    family_history_hypertension:string! \
    family_history_mental_health:string! \
    family_mental_health_details:text! \
    family_history_autoimmune:string! \
    family_history_kidney_disease:string! \
    family_history_lung_disease:string! \
    family_history_genetic:string! \
    family_genetic_details:text! \
    other_family_history:text! \
    family_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_social_history \
    assessment:references \
    smoking_status:string! \
    smoking_pack_years:double \
    smoking_quit_date:date \
    alcohol_use:string! \
    alcohol_units_per_week:double \
    recreational_drug_use:string! \
    recreational_drug_details:text! \
    caffeine_intake:string! \
    exercise_frequency:string! \
    exercise_type:text! \
    diet_description:string! \
    diet_details:text! \
    occupation:string! \
    employment_status:string! \
    occupational_hazards:text! \
    living_situation:string! \
    housing_type:string! \
    sexual_health_concerns:string! \
    travel_history:text! \
    social_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_review_of_systems \
    assessment:references \
    constitutional_fever:string! \
    constitutional_weight_loss:string! \
    constitutional_fatigue:string! \
    constitutional_night_sweats:string! \
    heent_headache:string! \
    heent_vision_changes:string! \
    heent_hearing_changes:string! \
    heent_sore_throat:string! \
    cardiovascular_chest_pain:string! \
    cardiovascular_palpitations:string! \
    cardiovascular_oedema:string! \
    cardiovascular_dyspnoea:string! \
    respiratory_cough:string! \
    respiratory_wheezing:string! \
    respiratory_shortness_of_breath:string! \
    gi_nausea:string! \
    gi_vomiting:string! \
    gi_abdominal_pain:string! \
    gi_diarrhoea:string! \
    gi_constipation:string! \
    gu_frequency:string! \
    gu_urgency:string! \
    gu_dysuria:string! \
    msk_joint_pain:string! \
    msk_muscle_pain:string! \
    msk_swelling:string! \
    msk_stiffness:string! \
    neuro_numbness:string! \
    neuro_tingling:string! \
    neuro_weakness:string! \
    neuro_dizziness:string! \
    neuro_seizures:string! \
    psych_depression:string! \
    psych_anxiety:string! \
    psych_sleep_disturbance:string! \
    skin_rash:string! \
    skin_itching:string! \
    skin_lesions:string! \
    additional_symptoms:text! \
    review_of_systems_notes:text! \
    --htmx

cargo loco generate scaffold assessment_consent_preferences \
    assessment:references \
    consent_to_treatment:string! \
    consent_to_share_records:string! \
    consent_to_research:string! \
    consent_to_contact_sms:string! \
    consent_to_contact_email:string! \
    consent_to_contact_phone:string! \
    preferred_contact_method:string! \
    preferred_appointment_time:string! \
    advance_directive:string! \
    advance_directive_details:text! \
    power_of_attorney:string! \
    power_of_attorney_details:text! \
    accessibility_needs:text! \
    special_requirements:text! \
    patient_signature_date:date \
    consent_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    risk_level:string! \
    risk_factor_count:int! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
